using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.Json;

namespace FaloopScreener;

/// <summary>Static hunt data extracted from faloop.app's own application bundle
/// (main.48dd7c05d52f96d1.js): every S/SS mark with its spawn window timings in hours
/// (normal and post-maintenance variants) and its English spawn trigger text.</summary>
internal static class FaloopData
{
    internal sealed record MobInfo(
        string Id, string Name, string Rank, string Expansion, string[] Zones,
        double Min, double Cap, double Excess, double MaintMin, double MaintCap, double MaintExcess);

    public static readonly string[] CrystalWorlds =
        ["balmung", "brynhildr", "coeurl", "diabolos", "goblin", "malboro", "mateus", "zalera"];

    public static IReadOnlyList<MobInfo> Mobs { get; } = LoadMobs();
    public static IReadOnlyDictionary<string, MobInfo> MobsById { get; } = Mobs.ToDictionary(m => m.Id);
    public static IReadOnlyDictionary<string, string> SpawnTriggers { get; } = LoadTriggers();

    public static string Pretty(string slug)
        => string.Join(' ', slug.Split('_').Select(w => w.Length > 0 ? char.ToUpperInvariant(w[0]) + w[1..] : w));

    private static List<MobInfo> LoadMobs()
    {
        var list = new List<MobInfo>();
        using var doc = JsonDocument.Parse(MobsJson);
        foreach (var e in doc.RootElement.EnumerateArray())
        {
            list.Add(new MobInfo(
                e.GetProperty("id").GetString()!,
                e.GetProperty("name").GetString()!,
                e.GetProperty("rank").GetString()!,
                e.GetProperty("exp").GetString()!,
                e.GetProperty("zones").EnumerateArray().Select(z => z.GetString()!).ToArray(),
                e.GetProperty("min").GetDouble(),
                e.GetProperty("cap").GetDouble(),
                e.GetProperty("excess").GetDouble(),
                e.GetProperty("mMin").GetDouble(),
                e.GetProperty("mCap").GetDouble(),
                e.GetProperty("mExcess").GetDouble()));
        }

        return list;
    }

    private static Dictionary<string, string> LoadTriggers()
    {
        var dict = new Dictionary<string, string>();
        using var doc = JsonDocument.Parse(TriggersJson);
        foreach (var p in doc.RootElement.EnumerateObject())
            dict[p.Name] = CleanMarkdown(p.Value.GetString() ?? string.Empty);
        return dict;
    }

    /// <summary>The trigger texts are written in the site's markdown: strip images,
    /// unwrap links to their text, and drop bold markers.</summary>
    private static string CleanMarkdown(string text)
    {
        text = System.Text.RegularExpressions.Regex.Replace(text, @"!\[[^\]]*\]\([^)]*\)\s*", "");
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\[([^\]]+)\]\([^)]*\)", "$1");
        return text.Replace("**", "").Trim();
    }

